arguments.file_text:
@using sv_5d078acea56d4b9da3b2b51a0b30d5ac.Models

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2c2f33;
    color: #e0e0e0;
    min-width: 200px;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_5d078acea56d4b9da3b2b51a0b30d5ac.Models
@inject IJSRuntime JS

<div class="message-list-container">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    else if (HasMore)
    {
        <div class="load-more">
            <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
        </div>
    }

    <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
        @foreach (var message in Messages)
        {
            var replyCount = GetReplyCount(message.Id);
            <MessageItem Message="message"
                         ThreadReplyCount="replyCount"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(message.Id)"
                         OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference messageListRef;

    private int GetReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task HandleScroll()
    {
        if (!HasMore || IsLoadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

.message-list-container {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

.load-more {
    text-align: center;
    padding: 8px;
}

.load-more-btn {
    background: none;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 6px 16px;
    font-size: 0.82rem;
    color: #4a90d9;
    cursor: pointer;
    transition: background-color 0.15s;
}

.load-more-btn:hover {
    background-color: #f0f4ff;
}

@using sv_5d078acea56d4b9da3b2b51a0b30d5ac.Models

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <MessageItem Message="RootMessage" ShowActions="false" />
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages)
            {
                <MessageItem Message="reply" ShowActions="false" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    border-left: 1px solid #e0e0e0;
    background: #fff;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.15s;
    line-height: 1;
}

.close-btn:hover {
    background-color: #f0f0f0;
    color: #333;
}

.thread-root-message {
    padding: 8px 0;
    border-bottom: 1px solid #f0f0f0;
    background: #fafafa;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.78rem;
    color: #888;
    border-bottom: 1px solid #f0f0f0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

