@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(isThreadOpen ? "" : "expanded")">
        @if (selectedChannel is not null)
        {
            <div class="channel-header-bar">
                <h2># @selectedChannel.Name</h2>
                <p>@selectedChannel.Description</p>
            </div>

            <MessageList Messages="messages"
                         ThreadSummaries="threadSummaries"
                         IsLoadingMore="isLoadingMore"
                         HasMore="hasMoreMessages"
                         OnLoadMore="LoadOlderMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private Channel? selectedChannel;
    private int selectedChannelId;

    private bool isThreadOpen;
    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private bool isLoadingMore;
    private bool hasMoreMessages;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = messages.Count >= PageSize;
        ComputeThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        CloseThreadSync();
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || selectedChannel is null) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        hasMoreMessages = older.Count >= PageSize;
        messages.InsertRange(0, older);
        ComputeThreadSummaries();
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThreadSync()
    {
        isThreadOpen = false;
        activeThreadRootId = null;
        threadRootMessage = null;
        threadMessages = [];
    }

    private Task CloseThread()
    {
        CloseThreadSync();
        return Task.CompletedTask;
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || activeThreadRootId is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, activeThreadRootId);
        threadMessages.Add(reply);
        ComputeThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: add or increment the reaction locally
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private void ComputeThreadSummaries()
    {
        threadSummaries = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt))
            );
    }
}

